from elasticsearch import Elasticsearch

es = Elasticsearch()

def search_customers(query: str, org_id: str) -> list:
    result = es.search(index='customers', body={
        'query': {
            'multi_match': {
                'query': query,
                'fields': ['name', 'email']
            }
        }
    })
    return [hit['_source'] for hit in result['hits']['hits']]
